async function setupCorsPlugin (app, cors) {
  let origin = cors.origin
  if (Array.isArray(origin)) {
    origin = origin.map(originToRegexp)
  } else {
    origin = originToRegexp(origin)
  }

  cors.origin = origin
  app.register(fastifyCors, cors)
}

