export async function createCategory(request: FastifyRequest<PostCategory>, reply: FastifyReply) {
  const { name } = request.body;

  let category = await request.server.prisma.category.create({
    data: {
      name,
    }
  });

  return reply.status(201).send(category);
}

export async function updateCategory(request: FastifyRequest<PutCategory>, reply: FastifyReply) {
  const { name } = request.body;
  const { id } = request.params;

  let category = await request.server.prisma.category.update({
    where: { id },
    data: { name },
  });

  return reply.status(200).send(category);
}

export async function getProduct(request: FastifyRequest<CrudIdRequest>, reply: FastifyReply) {
  const { id } = request.params;

  let product = await request.server.prisma.product.findUnique({
    where: { id },
    include: { category: true },
  });

  if (!product) {
    return reply.status(404).send({ message: 'Product not found' });
  }

  return reply.status(200).send(product);
}

export default function makeFindUsersQuery({ queryBus, userRepository }: Dependencies) {
  return {
    async handler({ payload }: HandlerAction<typeof findUsersQuery>): Promise<FindUsersResult> {
      const query = paginatedQueryBase(payload);
      return userRepository.findAllPaginatedFiltered(query, {
        country: query.country,
        postalCode: query.postalCode,
        street: query.street,
      });
    },
    init() {
      queryBus.register(findUsersQuery.type, this.handler);
    },
  };
}

function prepareOpenapiSchemas (opts, jsonSchemas, ref) {
  const openapiSchemas = {}

  for (const schemaName of Object.keys(jsonSchemas)) {
    const jsonSchema = { ...jsonSchemas[schemaName] }

    const resolvedJsonSchema = ref.resolve(jsonSchema, { externalSchemas: [jsonSchemas] })
    const openapiSchema = convertJsonSchemaToOpenapi3(opts, resolvedJsonSchema)
    resolveSchemaExamplesRecursive(openapiSchema)

    openapiSchemas[schemaName] = openapiSchema
  }
  return openapiSchemas
}

function buildConsumer (fastify, opts, next) {
  const consumer = new Consumer(opts.consumer, fastify.log, next, opts.consumerTopicConf, opts.metadataOptions)
  fastify.kafka.consumer = consumer
  fastify.kafka.consume = consumer.consume.bind(consumer)
  fastify.kafka.subscribe = consumer.subscribe.bind(consumer)
  fastify.kafka.on = consumer.on.bind(consumer)

  fastify.addHook('onClose', onClose)
  function onClose (fastify, done) {
    fastify.kafka.consumer.stop(done)
  }
}

async create(request: FastifyRequest<{ Body: Entity, Querystring: { $results: boolean } }>) {
  const { identifiers } = await this.model.create(request.body);

  if (get(request.query.$results, this.config.returning)) {
    return await this.model.find({ $where: { [this.config.id]: { $in: identifiers } } });
  }

  return identifiers;
}

async inject (injectParams, onInject) {
  const response = await this.#app.inject(injectParams, onInject)

  if (onInject) {
    return
  }

  const { statusCode, statusMessage, headers, body } = response
  return { statusCode, statusMessage, headers, body }
}

export function fastifyErrorMiddleware(
  error: FastifyError,
  _request: FastifyRequest,
  reply: FastifyReply
) {
  // The error strategy is to assume that errors that happened during a request are not fatal (vs errors that happened during the app initialization)
  const standardAppError = covertUnknownToAppError(error);
  standardAppError.isCatastrophic = false;
  const responseToRequest = errorHandler.handleError(standardAppError);
  reply.status(responseToRequest).send({});
}

function requireFastifyForModule (modulePath) {
  try {
    const basedir = path.resolve(process.cwd(), modulePath)
    const module = require(resolveFrom.silent(basedir, 'fastify') || 'fastify')

    return { module }
  } catch (e) {
    exit('unable to load fastify module')
  }
}

async function viewEdge (page, data, opts) {
  data = Object.assign({}, defaultCtx, this.locals, data)

  switch (typeof page) {
    case 'string':
      return engine.render(getPage(page, 'edge'), data)
    case 'function':
      return page(data)
    case 'object':
      return engine.renderRaw(page, data)
    default:
      throw new Error('Unknown page type')
  }
}

function withLayout (render, layout) {
  if (layout) {
    return async function (page, data, opts) {
      if (opts?.layout) throw new Error('A layout can either be set globally or on render, not both.')
      data = Object.assign({}, defaultCtx, this.locals, data)
      const result = await render.call(this, page, data, opts)
      data = Object.assign(data, { body: result })
      return render.call(this, layout, data, opts)
    }
  }
  return render
}

function resolveSchema(maybeSchema: $ZodType | { properties: $ZodType }): $ZodType {
  if (maybeSchema instanceof $ZodType) {
    return maybeSchema as $ZodType
  }
  if ('properties' in maybeSchema && maybeSchema.properties instanceof $ZodType) {
    return maybeSchema.properties as $ZodType
  }
  throw new InvalidSchemaError(JSON.stringify(maybeSchema))
}

export async function resolveDevViteConfig(root: string): Promise<ResolvedConfig> {
  const configFile = findConfigFile(root)
  if (!configFile) {
    throw new Error(`No Vite config file found. Searched for vite.config.{js,mjs,ts} in: ${root}`)
  }

  const { resolveConfig } = await import('vite')
  return await resolveConfig({ configFile }, 'serve', 'development')
}

