buildValidatorFunction ({ schema/*, method, url, httpPart */ }) {
  // Ajv does not support compiling two schemas with the same
  // id inside the same instance. Therefore if we have already
  // compiled the schema with the given id, we just return it.
  if (schema.$id) {
    const stored = this.ajv.getSchema(schema.$id)
    if (stored) {
      return stored
    }
  }

  return this.ajv.compile(schema)
}

async function ensureConfigFile(base: string, { renderer }: SetupOptions): Promise<string> {
  const sourcePath = join(renderer.path, 'config.mjs')
  const targetPath = join(base, 'vite.config.js')
  if (exists(sourcePath) && !exists(targetPath)) {
    const generatedConfig = await read(sourcePath, 'utf8')
    await write(targetPath, generatedConfig)
  }
  return targetPath
}

function loadVirtualModuleOverride(viteProjectRoot, virtualInput) {
  let virtual = virtualInput
  if (!virtualModules.includes(virtual) && !virtualModulesTS.includes(virtual)) {
    return
  }
  let overridePath = resolve(viteProjectRoot, virtual)
  if (existsSync(overridePath)) {
    return overridePath
  }
  overridePath = overridePath.replace('.js', '.ts')
  if (existsSync(overridePath)) {
    return overridePath
  }
}

export async function upgrade (logger, config, version) {
  const iterator = semgrator({
    version,
    path: resolve(import.meta.dirname, 'versions'),
    input: config,
    logger: logger?.child({ name: '@platformatic/service' }) ?? abstractLogger
  })

  let result

  for await (const updated of iterator) {
    result = updated.result
  }

  return result
}

